For NestJS service, you can instance and rewrite all methods. This is a good pattern following dependency inversion. In the future, if you need to replace Axios, you can reimplement the service, and all will be fine.

```ts
import { Inject, Injectable } from '@nestjs/common';
import axios, { AxiosInstance, AxiosRequestConfig } from 'axios';
import { HTTP_OPTIONS } from '../contants';

@Injectable()
export class HttpService {
  instance: AxiosInstance;

  constructor(@Inject(HTTP_OPTIONS) options: AxiosRequestConfig) {
    this.instance = axios.create(options);
  }

  post(url: string, data?: any, config?: AxiosRequestConfig) {
    return this.instance.post(url, data, config);
  }
}
```

