            if (error.name === 'AxiosError') {
              const toJSON = error.toJSON.bind(error);
              error.toJSON = () => ({
                ...toJSON(),
                response: {
                  data: error.response?.data,
                  headers: { ...error.response?.headers },
                },
              });
            }
            return error;
          }),
