I solved this by installing the interceptors at the module level based on the response to this question here:

https://community.auth0.com/t/how-to-get-token-from-outside-react-components/68756/3

```tsx
class Interceptor {
  auth0 = undefined;

  setAuth0(auth0) {
    this.auth0 = auth0;
  }

  requestInterceptor = async (config) => {
    if (this.auth0) {
      const hasCredentials = await this.auth0.hasValidCredentials();
      if (hasCredentials) {
        try {
          const credentials = await this.auth0.getCredentials();
          if (credentials) {
            config.headers.Authorization = `Bearer ${credentials.accessToken}`;
          }
        } catch (err) {
          console.log(err);
        }
      }
    }
    return config;
  };
}

const interceptor = new Interceptor();
axios.interceptors.request.use(interceptor.requestInterceptor);

export function AuthGuard(props) {
  const [init, setInit] = React.useState(false);
  const auth0 = useAuth0();

  React.useEffect(() => {
    if (auth0.isLoading) {
      return;
    }
    interceptor.setAuth0(auth0);
    setInit(true);

    return () => {
      setInit(false);
      interceptor.setAuth0(undefined);
    };
  }, [auth0]);

  return init ? props.children : null;
}
```

This means that `axios.interceptors.request.use` is called as soon as the app loads which seems to be enough to work around the Android issue.

