### Solution
Here’s a step-by-step solution to resolve the issue:

1. Ensure Proper Signal Handling
Bind the AbortController to the specific upload instance and persist it across renders using a useRef hook. This avoids creating a new AbortController for each render and ensures proper cancellation.

2. Properly Handle the Cancel Logic
Update the state only after confirming that the request has been canceled. This allows the catch block to handle the cancellation correctly.

### Updated Code
```tsx
"use client";

import React, { useCallback, useRef, useState } from "react";
import { useDropzone } from "react-dropzone";
import { Button } from "./ui/button";
import { Image, VideoIcon, X } from "lucide-react";
import { BarLoader } from "react-spinners";
import { IMAGE_MAX_UPLOAD_SIZE } from "@/constants";
import { toast } from "sonner";
import { FileUploaderProps } from "@/types";
import { generatePresignedUploadUrl } from "@/lib/s3";
import { formatForUrl } from "@/lib/utils";
import axios from "axios";

export default function FileUploader({
  type,
  onUploadComplete,
}: FileUploaderProps) {
  const [files, setFiles] = useState<File[]>([]);
  const [uploadProgress, setUploadProgress] = useState<number>(0);

  // Persist AbortController instance across renders
  const controllerRef = useRef<AbortController | null>(null);

  let acceptedFileType = type === "image" 
    ? { "image/*": ["*.png", "*.jpg", ".jpeg"] } 
    : { "video/*": ["*.mp4"] };

  const onDrop = useCallback(async (acceptedFiles: File[]) => {
    setFiles(acceptedFiles);
    const file = acceptedFiles[0];

    if (file.size > IMAGE_MAX_UPLOAD_SIZE && type === "image") {
      setFiles([]);
      toast.error(
        `Bild ist zu groß. Es muss kleiner als ${
          IMAGE_MAX_UPLOAD_SIZE / (1024 * 1024)
        } MB sein`,
        { position: "top-center" }
      );
      return;
    }

    // Create a new AbortController for the upload
    controllerRef.current = new AbortController();

    try {
      // Get the upload URL
      const uploadUrl = await generatePresignedUploadUrl(
        file.name,
        file.type,
        type
      );

      await axios.put(uploadUrl, file, {
        headers: { "Content-Type": file.type },
        signal: controllerRef.current.signal, // Attach the signal
        onUploadProgress: (progressEvent) => {
          if (!progressEvent.total) return;
          setUploadProgress(
            Math.round((progressEvent.loaded / progressEvent.total) * 100)
          );
        },
      });

      const fileUrl = `https://${
        process.env.NEXT_PUBLIC_S3_BUCKET
      }.s3.eu-central-1.amazonaws.com/${type}/${formatForUrl(file.name)}`;
      onUploadComplete(fileUrl);

    } catch (error) {
      if (axios.isCancel(error)) {
        console.log("Upload canceled");
        toast.error("Upload cancelled", { position: "top-center" });
      } else {
        console.error("Error uploading file: ", error);
        toast.error("Fehler beim Hochladen des Bildes", {
          position: "top-center",
        });
      }
    } finally {
      setUploadProgress(0);
      setFiles([]);
      controllerRef.current = null; // Reset controller
    }
  }, [type, onUploadComplete]);

  const { getRootProps, getInputProps } = useDropzone({
    onDrop,
    maxFiles: 1,
    accept: acceptedFileType,
  });

  return (
    <div {...getRootProps()} className="w-full">
      <input {...getInputProps()} />
      <Button type="button" size="lg" className="w-full">
        {type === "image" ? (
          <>
            <Image size={24} className="mr-4" />
            <p>Bild hinzufügen</p>
          </>
        ) : (
          <>
            <VideoIcon size={24} className="mr-4" />
            <p>Video hinzufügen</p>
          </>
        )}
      </Button>
      {files.length > 0 && (
        <div className="fixed bottom-10 right-10 bg-slate-100 p-6 z-50 rounded-lg space-y-2">
          <h4 className="text-xl">Uploading</h4>
          <div className="flex items-center gap-3">
            <div>
              <p className="text-xs">{files[0].name}</p>
              <BarLoader width={100} />
              {uploadProgress} %
            </div>
            <Button
              type="button"
              className="w-6 h-6 rounded-full bg-red-300 p-1"
              onClick={(e) => {
                if (controllerRef.current) {
                  controllerRef.current.abort();
                }
                e.stopPropagation();
              }}
            >
              <X className="h-4 w-4" />
            </Button>
          </div>
        </div>
      )}
    </div>
  );
}
```
### Key Changes
useRef for Controller Persistence:
The AbortController instance is maintained using useRef, ensuring it persists across renders.

Proper Cancellation Handling:

Aborted requests are correctly captured in the catch block.
State reset (setFiles, setUploadProgress) happens after the cancellation logic is executed.
Cleanup in finally:
The AbortController instance is reset to null after each upload attempt.

This approach ensures that cancellation works reliably with the AbortController API.

