I've tested the PR I've raised and can confirm it resolves this very simple problem.

// Replicate encode() locally (not ideal)
const encode = (val) => {
  return encodeURIComponent(val)
    .replace(/%40/gi, '@')
    .replace(/%3A/gi, ':')
    .replace(/%24/g, '$')
    .replace(/%2C/gi, ',')
    .replace(/%20/g, '+')
    .replace(/%5B/gi, '[')
    .replace(/%5D/gi, ']');
};

// Custom params serializer using the copied encode
axios.get('/endpoint', {
  params: { a: 'value', b: 'value' },
  paramsSerializer: {
    serialize: (params) => {
      const parts = [];
      for (const key in params) {
        const val = params[key];
        if (val != null) {
          parts.push(`${encode(key)}=${encode(val)}`);
        }
      }
      return parts.join('&');
    }
  }
});

