In my case this happens, because by default it uses the node distribution file of axios.js instead of the esm distribution file.

This issue can happen to other libraries also, so check for the paths and usage of the correct distribution files, in the "./node_modules/<library_name  | axios>/dist/".

Add this to your metro.config.js file or change it accordingly.
Here is my metro config for this:

```
const path = require('path');
const originalResolveRequest = config.resolver.resolveRequest;
config.resolver.resolveRequest = (context, moduleName, platform) => {

    if (moduleName === 'axios') {
        return {
            filePath: path.resolve('node_modules/axios/dist/esm/axios.js'),
            type: 'sourceFile',
        };
    }
    return originalResolveRequest
        ? originalResolveRequest(context, moduleName, platform)
        : context.resolveRequest(context, moduleName, platform);
};
