// Create error with circular cause
const mockError = new Error('Test');
mockError.circular = { ref: mockError };
const axiosError = axios.AxiosError.from(mockError, 'TEST');

try {
  const json = JSON.stringify(axiosError);
  console.log('✓ Success:', json.length, 'chars');
} catch (e) {
