// Patch expo's broken ReadableStream polyfill so axios's fetch adapter
// detection doesn't crash when it tries to cancel a stream that has a reader.
// The polyfill returns a rejected Promise (not a sync throw), so we must
// suppress the rejection by catching it.
if (typeof ReadableStream !== 'undefined') {
  const originalCancel = ReadableStream.prototype.cancel
  ReadableStream.prototype.cancel = function (reason?: unknown) {
    const result = originalCancel.call(this, reason)
    // result may be a rejected Promise — swallow it so axios's feature
    // detection (which wraps the call in try/catch for sync errors) doesn't
    // surface an unhandled rejection.
    if (result && typeof result.then === 'function') {
      return result.then(undefined, () => undefined)
    }
    return result
  }
}
